using Microsoft.EntityFrameworkCore;
using Microsoft.EntityFrameworkCore.ChangeTracking;
using Microsoft.EntityFrameworkCore.ValueGeneration;

class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(b =>
        {
            b.ToContainer("Products");

            // BREAKING CHANGE 1 — Discriminator property renamed "$type" in EF Core 9.
            // Preserve "Discriminator" so existing documents and raw SQL queries keep working.
            b.HasDiscriminator<string>("Discriminator")
                .HasValue<Product>("Product");

            // BREAKING CHANGE 2 — id values no longer include the entity-type prefix.
            // EF8 wrote "Product|123"; EF9 writes "123".
            // Preserve the old format so lookups against 500K existing docs still resolve.
            b.Property<string>("__id")
                .ToJsonProperty("id")
                .HasValueGenerator<LegacyCosmosIdGenerator>();

            // BREAKING CHANGE 3 — HasIndex now throws for the Cosmos provider
            // instead of being silently ignored.  Removed the HasIndex(p => p.Sku) call.
            // Manage indexing policy via Azure Portal / ARM / Bicep.
        });
    }
}

class Product
{
    public int Id { get; set; }
    public string Sku { get; set; } = default!;
}

/// <summary>
/// Reproduces the EF Core 8 id format ("EntityType|PrimaryKey") so that
/// new writes remain compatible with the 500K existing documents.
/// </summary>
class LegacyCosmosIdGenerator : ValueGenerator<string>
{
    public override bool GeneratesTemporaryValues => false;

    public override string Next(EntityEntry entry)
    {
        var pk = entry.Metadata.FindPrimaryKey()!.Properties[0];
        var value = entry.Property(pk.Name).CurrentValue;
        return $"{entry.Metadata.ShortName()}|{value}";
    }
}

