class CosmosQuery
{
    // BREAKING CHANGE 4 — Synchronous I/O APIs removed in EF Core 9 Cosmos provider.
    // ToList(), First(), Single(), etc. must become their Async counterparts.
    async Task FindProducts(ProductContext ctx)
    {
        // Raw SQL still works because we preserved the "Discriminator" JSON property name.
